+                        "Use a connector directory name such as `github` or `slack`.".to_owned(),
+                    ],
+                }),
+                exit_code: CliExitCode::Validation,
+            });
+        };
+
+        let mut payload = json!({
+            "status": "ok",
+            "command": "audit",
+            "subcommand": "matrix",
+            "source": "workspace-manifests",
