+        entry.operations.count,
+        entry.operations.completeness * 100.0
+    );
+    let _ = writeln!(
+        out,
+        "  Agent hints: {:.0}% coverage",
+        entry.agent_hints.coverage * 100.0
+    );
+    if entry.gaps.is_empty() {
+        let _ = writeln!(out, "  Gaps:       none");
+    } else {
