+                cat = gap.category,
+                msg = gap.description,
+            );
+        }
+    }
+    out
+}
+
+fn format_audit_gaps_toon(gaps: &[AuditGapReport], blocking_only: bool) -> String {
+    use std::fmt::Write;
+
+    if gaps.is_empty() {
+        return "No gaps found.".to_owned();
+    }
+
+    let mut out = String::new();
+    let _ = writeln!(
+        out,
+        "Gaps: {} found{}",
+        gaps.len(),
+        if blocking_only {
+            " (blocking only)"
+        } else {
+            ""
+        }
+    );
+    let _ = writeln!(out);
+    for gap in gaps {
+        let _ = writeln!(
+            out,
+            "  [{sev}] {connector}: [{cat}] {msg}",
+            sev = gap.severity,
+            connector = gap.connector,
+            cat = gap.category,
+            msg = gap.message,
+        );
+    }
+    out
+}
